// // This module is designed to count down from 15 to 0 on each rising edge of the clock signal when the enable signal is high. If the reset signal is low, the counter will reset to 15.
module binary_up_counter(
    input wire clk,
    input wire rst_n,
    input wire en,
    output reg [3:0] count
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        count <= 4'd0;
    else if (en)
        count <= count + 4'd1;
end

endmodule
